INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 7, 0, 11, 943, 1, "ずいぶんと色々なものが流れているね。\nここがプールでないなら、\n魚が潜んでいそうだけど…", 1, 0, 19430025, 122511);
INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES ("", "", "", 91, 943, "", "", "", "", 19430026, 0);
