INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 10, 0, 11, 944, 1, "なんだ、ユカリだったかにゃ。\n何ってもちろん商売にゃ！", 1, 0, 19440033, 107911);
