INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0, 10, 0, 11, 944, 1, "こんなに人がいっぱいいる商機、\n見逃すわけにはいかないにゃ！", 1, 0, 19440038, 107911);
