INSERT INTO `v1_85da6ae8725f986b23d90ba88af211c1f8349b338b46cefeb64c627c2e691e8d` VALUES (0.1, 0, 0.1, 3, 945, "45_yui_shy_loop", "45_yui_shy_in", "", 1, 19450031, 1);
